/**
 * metrics-emitter tests — M168 Phase 5 (#1915).
 *
 * Verifies the async counter contract: increments are synchronous + O(1), the
 * flush is deferred to setImmediate (no hot-path I/O), counters accumulate and
 * reset, and the opt-out env var fully disables emission. node:fs/promises is
 * mocked so the test never touches ~/.local/state.
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';

// vi.mock is hoisted above module scope, so the mock fns must be created inside
// vi.hoisted() — referencing plain consts here would hit a ReferenceError.
const { appendFile, mkdir } = vi.hoisted(() => ({
  appendFile: vi.fn((_path: string, _data: string, _enc?: string) => Promise.resolve()),
  mkdir: vi.fn((_path: string, _opts?: unknown) => Promise.resolve(undefined)),
}));
vi.mock('node:fs/promises', () => ({ appendFile, mkdir }));

import { incrementMetric, __metricsInternals, METRICS_PATH } from '../../lib/metrics-emitter.js';

const flushTick = () => new Promise<void>((r) => setImmediate(r));

describe('metrics-emitter (#1915)', () => {
  beforeEach(() => {
    appendFile.mockClear();
    mkdir.mockClear();
    __metricsInternals.counters.clear();
    delete process.env.ORK_DISABLE_COORDINATION_METRICS;
  });
  afterEach(() => {
    delete process.env.ORK_DISABLE_COORDINATION_METRICS;
  });

  it('increments synchronously into the in-process counter (no immediate I/O)', () => {
    incrementMetric('sessions_db_write');
    incrementMetric('sessions_db_write');
    expect(__metricsInternals.counters.get('sessions_db_write')).toBe(2);
    // The write is deferred — nothing hit disk on the hot path.
    expect(appendFile).not.toHaveBeenCalled();
  });

  it('flushes via setImmediate, appends one JSONL line per metric, and resets', async () => {
    incrementMetric('sessions_db_write', 3);
    incrementMetric('lock_acquired');
    await flushTick();
    await flushTick(); // let the mocked promise chain settle

    expect(appendFile).toHaveBeenCalledTimes(1);
    const [path, payload] = appendFile.mock.calls[0];
    expect(path).toBe(METRICS_PATH);
    const lines = String(payload).trim().split('\n').map((l) => JSON.parse(l));
    const byMetric = Object.fromEntries(lines.map((l) => [l.metric, l.count]));
    expect(byMetric.sessions_db_write).toBe(3);
    expect(byMetric.lock_acquired).toBe(1);
    expect(lines.every((l) => typeof l.ts === 'string')).toBe(true);
    // Counters reset after flush so the next window starts clean.
    expect(__metricsInternals.counters.size).toBe(0);
  });

  it('coalesces a burst of increments into a single flush (one setImmediate)', async () => {
    for (let i = 0; i < 50; i++) incrementMetric('sessions_db_write');
    await flushTick();
    await flushTick();
    expect(appendFile).toHaveBeenCalledTimes(1);
    expect(JSON.parse(String(appendFile.mock.calls[0][1]).trim()).count).toBe(50);
  });

  it('fully no-ops when ORK_DISABLE_COORDINATION_METRICS=1', async () => {
    process.env.ORK_DISABLE_COORDINATION_METRICS = '1';
    incrementMetric('sessions_db_write');
    await flushTick();
    expect(__metricsInternals.counters.size).toBe(0);
    expect(appendFile).not.toHaveBeenCalled();
  });
});
